        private static bool TryDeserialize<T>(string payloadJson, out object requestDto, out string errorMessage)
            where T : class
        {
            requestDto = null;
            errorMessage = null;

            if (string.IsNullOrWhiteSpace(payloadJson))
            {
                errorMessage = "SSOT payload JSON is empty.";
                return false;
            }

            try
            {
                var parsed = JsonUtility.FromJson<T>(payloadJson);
                if (parsed == null)
                {
                    errorMessage = "SSOT payload deserialization returned null for type " + typeof(T).Name + ".";
                    return false;
                }

                requestDto = parsed;
                return true;
            }
            catch (Exception ex)
            {
                errorMessage = "SSOT payload deserialization failed for type " + typeof(T).Name + ": " + ex.Message;
                return false;
            }
        }
    }
